@media (max-width: 719px) {
	.ombox > * > tr {
		display: block;
	}
	.ombox .mbox-image {
		float: left;
		padding-top: 14px;
		padding-right: 6px;
	}
	.ombox .mbox-text,
	.ombox .mbox-imageright {
		display: block;
		box-sizing: border-box;
	}
	.ombox .mbox-imageright {
		float: right;
		clear: right;
	}
}

